const fs = require('fs');
const path = require('path');

// Base64 de un favicon.ico transparente de 1x1
const base64Icon = '';

const targetPath = path.join(__dirname, '../public/favicon.ico');
fs.writeFileSync(targetPath, Buffer.from(base64Icon, 'base64'));
console.log('Favicon.ico creado exitosamente en:', targetPath);
